//! # mosaic-emit-webcomponent — Emitting Web Components Custom Element classes.
//!
//! This crate is the Web Components backend for the Mosaic compiler. It
//! implements [`MosaicRenderer`] and is driven by [`MosaicVM`]. The output is a
//! JavaScript string containing a complete Custom Element class ready to be
//! registered with `customElements.define`.
//!
//! ## Output file structure
//!
//! ```javascript
//! // Auto-generated by mosaic-emit-webcomponent. Do not edit.
//!
//! class ProfileCard extends HTMLElement {
//!   static get observedAttributes() { return ['avatar-url', 'display-name']; }
//!
//!   constructor() {
//!     super();
//!     this.attachShadow({ mode: 'open' });
//!   }
//!
//!   connectedCallback() { this._render(); }
//!   attributeChangedCallback() { this._render(); }
//!
//!   _render() {
//!     this.shadowRoot.innerHTML = `
//!       <div style="display: flex; flex-direction: column;">
//!         <span>${this.getAttribute('display-name') ?? ''}</span>
//!       </div>
//!     `;
//!   }
//! }
//! customElements.define('profile-card', ProfileCard);
//! ```
//!
//! ## Architecture: string accumulation
//!
//! Unlike the React renderer which uses a stack of buffers, the Web Component
//! renderer builds a flat HTML template string. The stack is still used to
//! track open/close tags in the right order.
//!
//! ## Primitive node → HTML element mapping
//!
//! | Mosaic  | HTML tag                                   |
//! |---------|--------------------------------------------|
//! | Box     | `<div>`                                    |
//! | Column  | `<div style="display:flex;flex-direction:column">` |
//! | Row     | `<div style="display:flex;flex-direction:row">` |
//! | Text    | `<span>`                                   |
//! | Image   | `<img src="..." alt="...">`                |
//! | Spacer  | `<div style="flex:1">`                     |
//! | Scroll  | `<div style="overflow:auto">`              |
//! | Divider | `<hr>`                                     |
//! | Stack   | `<div style="position:relative">`          |
//! | Icon    | `<span class="icon">`                      |

use mosaic_vm::{EmitResult, MosaicRenderer, ResolvedProperty, ResolvedValue};
use mosaic_analyzer::{MosaicSlot, MosaicType};

// ===========================================================================
// WebComponentRenderer
// ===========================================================================

/// The Web Components backend for the Mosaic compiler.
///
/// # Example
///
/// ```no_run
/// use mosaic_emit_webcomponent::WebComponentRenderer;
/// use mosaic_vm::MosaicVM;
/// use mosaic_analyzer::analyze;
///
/// let file = analyze("component Label { slot text: text; Text { content: @text; } }").unwrap();
/// let vm = MosaicVM::new(file);
/// let result = vm.run(WebComponentRenderer::new()).unwrap();
/// println!("{}", result.output);
/// ```
pub struct WebComponentRenderer {
    component_name: String,
    slots: Vec<MosaicSlot>,
    /// Stack of (open_tag, close_tag) pairs and accumulated inner HTML.
    stack: Vec<HtmlFrame>,
    /// Accumulated HTML lines at the root level.
    root_lines: Vec<String>,
}

struct HtmlFrame {
    close_tag: String,
    inner: Vec<String>,
}

impl WebComponentRenderer {
    /// Create a new `WebComponentRenderer`.
    pub fn new() -> Self {
        Self {
            component_name: String::new(),
            slots: Vec::new(),
            stack: Vec::new(),
            root_lines: Vec::new(),
        }
    }

    /// Convert a PascalCase component name to kebab-case for the custom element tag.
    ///
    /// Examples:
    ///   `ProfileCard` → `profile-card`
    ///   `Button` → `button`
    fn to_element_tag(name: &str) -> String {
        let mut result = String::new();
        for (i, ch) in name.chars().enumerate() {
            if ch.is_uppercase() && i > 0 {
                result.push('-');
            }
            result.push(ch.to_ascii_lowercase());
        }
        result
    }

    /// Build an inline style string from resolved properties.
    fn build_style(props: &[ResolvedProperty]) -> String {
        let skip = ["content", "source", "a11y-label", "a11y-role", "a11y-hidden", "style"];
        let entries: Vec<String> = props
            .iter()
            .filter(|p| !skip.contains(&p.name.as_str()))
            .map(|p| {
                let css_name = &p.name; // already kebab-case
                let val = resolved_value_to_css(&p.value);
                format!("{css_name}:{val}")
            })
            .collect();
        entries.join(";")
    }

    /// Build the opening HTML tag for a primitive Mosaic node.
    fn primitive_open(tag: &str, props: &[ResolvedProperty]) -> (String, String) {
        // Returns (open_tag, close_tag).
        let extra_style = Self::build_style(props);
        let class = props
            .iter()
            .find(|p| p.name == "style")
            .map(|p| match &p.value {
                ResolvedValue::Enum { namespace, member } => {
                    format!("mosaic-{namespace}-{member}")
                }
                ResolvedValue::String(s) => s.clone(),
                _ => String::new(),
            })
            .unwrap_or_default();

        match tag {
            "Box" => {
                let combined = combine_styles("", &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Stack" => {
                let base = "position:relative";
                let combined = combine_styles(base, &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Column" => {
                let base = "display:flex;flex-direction:column";
                let combined = combine_styles(base, &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Row" => {
                let base = "display:flex;flex-direction:row";
                let combined = combine_styles(base, &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Text" => {
                let mut attrs = String::new();
                if !extra_style.is_empty() {
                    attrs.push_str(&format!(" style=\"{extra_style}\""));
                }
                if !class.is_empty() {
                    attrs.push_str(&format!(" class=\"{class}\""));
                }
                (format!("<span{attrs}>"), "</span>".into())
            }
            "Image" => {
                let src = props
                    .iter()
                    .find(|p| p.name == "source")
                    .map(|p| resolved_value_to_css(&p.value))
                    .unwrap_or_default();
                let alt = props
                    .iter()
                    .find(|p| p.name == "a11y-label")
                    .map(|p| resolved_value_to_css(&p.value))
                    .unwrap_or_default();
                (format!("<img src=\"{src}\" alt=\"{alt}\">"), String::new())
            }
            "Spacer" => {
                let base = "flex:1";
                let combined = combine_styles(base, &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Scroll" => {
                let base = "overflow:auto";
                let combined = combine_styles(base, &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
            "Divider" => ("<hr>".into(), String::new()),
            "Icon" => {
                let class_val = if class.is_empty() {
                    "icon".to_string()
                } else {
                    format!("icon {class}")
                };
                (format!("<span class=\"{class_val}\">"), "</span>".into())
            }
            _ => {
                let combined = combine_styles("", &extra_style);
                let open = format_html_div(&combined, &class, props);
                (open, "</div>".into())
            }
        }
    }

    /// Get the content HTML for a Text node's `content` property.
    fn get_content(tag: &str, props: &[ResolvedProperty]) -> Option<String> {
        if tag != "Text" {
            return None;
        }
        props
            .iter()
            .find(|p| p.name == "content")
            .map(|p| resolved_value_to_html_content(&p.value))
    }

}

impl Default for WebComponentRenderer {
    fn default() -> Self {
        Self::new()
    }
}

impl MosaicRenderer for WebComponentRenderer {
    fn begin_component(&mut self, name: &str, slots: &[MosaicSlot]) {
        self.component_name = name.to_string();
        self.slots = slots.to_vec();
    }

    fn end_component(&mut self) {}

    fn begin_node(&mut self, tag: &str, is_primitive: bool, props: &[ResolvedProperty]) {
        let (open, close) = if is_primitive {
            Self::primitive_open(tag, props)
        } else {
            let elem = Self::to_element_tag(tag);
            (format!("<{elem}>"), format!("</{elem}>"))
        };

        // Get direct text content for Text nodes.
        let content = if is_primitive { Self::get_content(tag, props) } else { None };

        let mut frame = HtmlFrame {
            close_tag: close,
            inner: Vec::new(),
        };

        if let Some(text) = content {
            frame.inner.push(text);
        }

        // Prepend the open tag to whatever the parent will accumulate.
        // We store the open tag as the first line of inner, so flush can reconstruct.
        // Actually, we need to store open tags separately — let's use a wrapper approach.
        // Store the open tag as a sentinel by prepending it to inner with a marker.
        // Simpler: store open+close separately in the frame.
        // Re-design: store (open, close, inner) tuple.
        // We'll just push open onto the parent right now and push close after children.
        if let Some(parent) = self.stack.last_mut() {
            parent.inner.push(open);
        } else {
            self.root_lines.push(open);
        }

        self.stack.push(frame);
    }

    fn end_node(&mut self, _tag: &str) {
        if let Some(frame) = self.stack.pop() {
            let inner = frame.inner.join("");
            let close = frame.close_tag;
            // Append inner + close to parent (or root).
            if let Some(parent) = self.stack.last_mut() {
                parent.inner.push(format!("{inner}{close}"));
            } else {
                self.root_lines.push(format!("{inner}{close}"));
            }
        }
    }

    fn render_slot_child(&mut self, slot_name: &str, _slot_type: &MosaicType) {
        // Use a <slot name="…"> element for projection.
        let html = format!("<slot name=\"{slot_name}\"></slot>");
        if let Some(frame) = self.stack.last_mut() {
            frame.inner.push(html);
        } else {
            self.root_lines.push(html);
        }
    }

    fn begin_when(&mut self, slot_name: &str) {
        // Emit a template comment and a script-driven conditional wrapper.
        // In raw HTML template, we use a data-when attribute on a <template> tag.
        let html = format!("<template data-when=\"{slot_name}\">");
        if let Some(frame) = self.stack.last_mut() {
            frame.inner.push(html);
        } else {
            self.root_lines.push(html);
        }
    }

    fn end_when(&mut self) {
        let html = "</template>".to_string();
        if let Some(frame) = self.stack.last_mut() {
            frame.inner.push(html);
        } else {
            self.root_lines.push(html);
        }
    }

    fn begin_each(&mut self, slot_name: &str, item_name: &str, _element_type: &MosaicType) {
        let html = format!("<template data-each=\"{slot_name}\" data-as=\"{item_name}\">");
        if let Some(frame) = self.stack.last_mut() {
            frame.inner.push(html);
        } else {
            self.root_lines.push(html);
        }
    }

    fn end_each(&mut self) {
        let html = "</template>".to_string();
        if let Some(frame) = self.stack.last_mut() {
            frame.inner.push(html);
        } else {
            self.root_lines.push(html);
        }
    }

    fn emit(self) -> EmitResult {
        let element_tag = Self::to_element_tag(&self.component_name);

        // observedAttributes list.
        let observed: Vec<String> = self
            .slots
            .iter()
            .map(|s| format!("'{}'", s.name))
            .collect();
        let observed_str = observed.join(", ");

        // The HTML template body.
        let html_body = self.root_lines.join("");

        let output = format!(
            r#"// Auto-generated by mosaic-emit-webcomponent. Do not edit.

class {name} extends HTMLElement {{
  static get observedAttributes() {{ return [{observed}]; }}

  constructor() {{
    super();
    this.attachShadow({{ mode: 'open' }});
  }}

  connectedCallback() {{ this._render(); }}
  attributeChangedCallback() {{ this._render(); }}

  _render() {{
    this.shadowRoot.innerHTML = `{html}`;
  }}
}}
customElements.define('{tag}', {name});
"#,
            name = self.component_name,
            observed = observed_str,
            html = html_body,
            tag = element_tag,
        );

        EmitResult {
            output,
            component_name: self.component_name,
        }
    }
}

// ===========================================================================
// Helpers
// ===========================================================================

/// Convert a `ResolvedValue` to a CSS value string.
fn resolved_value_to_css(v: &ResolvedValue) -> String {
    match v {
        ResolvedValue::String(s) => s.clone(),
        ResolvedValue::Number(n) => n.to_string(),
        ResolvedValue::Dimension(n, unit) => match unit.as_str() {
            "dp" | "sp" => format!("{n}px"),
            "%" => format!("{n}%"),
            _ => format!("{n}{unit}"),
        },
        ResolvedValue::Color(r, g, b, a) => {
            if *a == 255 {
                format!("rgb({r},{g},{b})")
            } else {
                let alpha = *a as f64 / 255.0;
                format!("rgba({r},{g},{b},{alpha:.3})")
            }
        }
        ResolvedValue::Bool(b) => b.to_string(),
        ResolvedValue::SlotRef { name, .. } => {
            format!("${{this.getAttribute('{name}') ?? ''}}")
        }
        ResolvedValue::Enum { namespace, member } => format!("{namespace}-{member}"),
    }
}

/// Convert a `ResolvedValue` to an HTML text content string (for Text nodes).
fn resolved_value_to_html_content(v: &ResolvedValue) -> String {
    match v {
        ResolvedValue::String(s) => s.clone(),
        ResolvedValue::SlotRef { name, .. } => {
            format!("${{this.getAttribute('{name}') ?? ''}}")
        }
        other => resolved_value_to_css(other),
    }
}

/// Combine two CSS style strings, inserting a semicolon separator as needed.
fn combine_styles(base: &str, extra: &str) -> String {
    match (base.is_empty(), extra.is_empty()) {
        (true, true) => String::new(),
        (true, false) => extra.to_string(),
        (false, true) => base.to_string(),
        (false, false) => format!("{base};{extra}"),
    }
}

/// Format an HTML `<div>` with optional style and class attributes.
fn format_html_div(style: &str, class: &str, props: &[ResolvedProperty]) -> String {
    let mut attrs = Vec::new();
    if !style.is_empty() {
        attrs.push(format!("style=\"{style}\""));
    }
    if !class.is_empty() {
        attrs.push(format!("class=\"{class}\""));
    }
    // a11y attributes.
    for p in props {
        match p.name.as_str() {
            "a11y-label" => attrs.push(format!("aria-label=\"{}\"", resolved_value_to_css(&p.value))),
            "a11y-role" => attrs.push(format!("role=\"{}\"", resolved_value_to_css(&p.value))),
            "a11y-hidden" => attrs.push(format!("aria-hidden=\"{}\"", resolved_value_to_css(&p.value))),
            _ => {}
        }
    }
    if attrs.is_empty() {
        "<div>".into()
    } else {
        format!("<div {}>", attrs.join(" "))
    }
}

// ===========================================================================
// Tests
// ===========================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use mosaic_vm::MosaicVM;
    use mosaic_analyzer::analyze;

    fn emit(src: &str) -> String {
        let file = analyze(src).unwrap();
        let vm = MosaicVM::new(file);
        vm.run(WebComponentRenderer::new()).unwrap().output
    }

    // -----------------------------------------------------------------------
    // Test 1: Output contains class declaration
    // -----------------------------------------------------------------------

    #[test]
    fn test_class_declaration() {
        let out = emit(r#"component Button { Box { } }"#);
        assert!(out.contains("class Button extends HTMLElement"), "Missing class: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 2: customElements.define with kebab-case tag
    // -----------------------------------------------------------------------

    #[test]
    fn test_custom_elements_define() {
        let out = emit(r#"component ProfileCard { Box { } }"#);
        assert!(
            out.contains("customElements.define('profile-card', ProfileCard)"),
            "Missing customElements.define: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 3: observedAttributes from slots
    // -----------------------------------------------------------------------

    #[test]
    fn test_observed_attributes() {
        // Note: slot name must not be a keyword — use "title" not "text".
        let out = emit(r#"component Label { slot title: text; Text { content: @title; } }"#);
        assert!(out.contains("observedAttributes"), "Missing observedAttributes");
        assert!(out.contains("'title'"), "Missing slot in observedAttributes");
    }

    // -----------------------------------------------------------------------
    // Test 4: attachShadow present
    // -----------------------------------------------------------------------

    #[test]
    fn test_shadow_dom() {
        let out = emit(r#"component X { Box { } }"#);
        assert!(out.contains("attachShadow"), "Missing attachShadow: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 5: _render method present
    // -----------------------------------------------------------------------

    #[test]
    fn test_render_method() {
        let out = emit(r#"component X { Box { } }"#);
        assert!(out.contains("_render()"), "Missing _render method: {out}");
        assert!(out.contains("shadowRoot.innerHTML"), "Missing shadowRoot.innerHTML: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 6: Column → flex column style
    // -----------------------------------------------------------------------

    #[test]
    fn test_column_style() {
        let out = emit(r#"component X { Column { } }"#);
        assert!(
            out.contains("flex-direction:column") || out.contains("flex-direction: column"),
            "Expected flex-direction:column: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 7: Row → flex row style
    // -----------------------------------------------------------------------

    #[test]
    fn test_row_style() {
        let out = emit(r#"component X { Row { } }"#);
        assert!(
            out.contains("flex-direction:row") || out.contains("flex-direction: row"),
            "Expected flex-direction:row: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 8: Slot reference as child → <slot> element
    // -----------------------------------------------------------------------

    #[test]
    fn test_slot_child_element() {
        let out = emit(r#"component Container { slot header: node; Column { @header; } }"#);
        assert!(out.contains("<slot name=\"header\">"), "Expected <slot name=\"header\">: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 9: when block uses <template data-when>
    // -----------------------------------------------------------------------

    #[test]
    fn test_when_template() {
        let out = emit(r#"
          component Cond {
            slot show: bool;
            Column {
              when @show {
                Text { content: "Hi"; }
              }
            }
          }
        "#);
        assert!(out.contains("data-when=\"show\""), "Expected data-when: {out}");
        assert!(out.contains("</template>"), "Expected </template>: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 10: each block uses <template data-each>
    // -----------------------------------------------------------------------
    // NOTE: Uses list<text> which requires a grammar fix in the Rust parser.

    #[test]
    #[ignore = "Rust GrammarParser resolves 'list' as KEYWORD before list_type"]
    fn test_each_template() {
        let out = emit(r#"
          component List {
            slot items: list<text>;
            Column {
              each @items as item {
                Text { content: @item; }
              }
            }
          }
        "#);
        assert!(out.contains("data-each=\"items\""), "Expected data-each: {out}");
        assert!(out.contains("data-as=\"item\""), "Expected data-as: {out}");
    }
}
